/**
 * Função principal para injetar o mapa no container
 * @param {string} containerId - ID do elemento container onde o mapa será injetado
 */
function injectMap(containerId) {
    const container = document.getElementById(containerId);
    
    if (!container) {
        console.error(`Elemento com ID "${containerId}" não encontrado`);
        return;
    }
    
    // Criar elemento SVG
    const svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
    svg.setAttribute('viewBox', maranhaoMapData.viewBox);
    svg.setAttribute('width', '100%');
    svg.setAttribute('height', '100%');
    svg.setAttribute('preserveAspectRatio', 'xMidYMid meet');
    svg.classList.add('map-ma-svg');
    
    // Renderizar cada região
    maranhaoMapData.regions.forEach(region => {
        // Criar grupo para a região (facilita manipulação conjunta de path e label)
        const group = document.createElementNS('http://www.w3.org/2000/svg', 'g');
        group.classList.add('region-group');
        group.setAttribute('data-region', region.id);
        
        // Criar path da região
        const path = document.createElementNS('http://www.w3.org/2000/svg', 'path');
        path.setAttribute('d', region.path);
        path.setAttribute('id', region.id);
        path.setAttribute('data-region', region.id);
        path.classList.add('region-path');
        
        // Criar label de texto
        const label = document.createElementNS('http://www.w3.org/2000/svg', 'text');
        label.setAttribute('x', region.labelPos.x);
        label.setAttribute('y', region.labelPos.y);
        label.setAttribute('text-anchor', 'middle');
        label.setAttribute('dominant-baseline', 'middle');
        label.classList.add('region-label');
        label.textContent = region.name;
        
        // Adicionar path e label ao grupo
        group.appendChild(path);
        group.appendChild(label);
        
        // Adicionar grupo ao SVG
        svg.appendChild(group);
    });
    
    // Limpar container e adicionar SVG
    container.innerHTML = '';
    container.appendChild(svg);
    
    // Inicializar interatividade
    initializeMapInteractivity();
}

/**
 * Inicializa a interatividade do mapa
 * Conecta com a lógica de clique e seleção de regiões
 */
function initializeMapInteractivity() {
    const regionPaths = document.querySelectorAll('.region-path');
    
    regionPaths.forEach(path => {
        path.addEventListener('click', function() {
            const regionId = this.getAttribute('data-region');
            
            // Remover classe active de todos os paths
            regionPaths.forEach(p => p.classList.remove('active'));
            
            // Adicionar classe active ao path clicado
            this.classList.add('active');
            
            // Disparar evento customizado para que o HTML possa capturar
            const event = new CustomEvent('regionSelected', {
                detail: { regionId: regionId }
            });
            document.dispatchEvent(event);
        });
        
        // Adicionar efeito hover
        path.addEventListener('mouseenter', function() {
            this.style.filter = 'brightness(1.1)';
        });
        
        path.addEventListener('mouseleave', function() {
            if (!this.classList.contains('active')) {
                this.style.filter = 'brightness(1)';
            }
        });
    });
}

/**
 * Função auxiliar para obter dados de uma região específica
 * @param {string} regionId - ID da região
 * @returns {Object} Dados da região
 */
function getRegionData(regionId) {
    return maranhaoMapData.regions.find(r => r.id === regionId);
}

/**
 * Função auxiliar para destacar uma região programaticamente
 * @param {string} regionId - ID da região a destacar
 */
function highlightRegion(regionId) {
    const path = document.getElementById(regionId);
    if (path) {
        // Remover destaque de outras regiões
        document.querySelectorAll('.region-path').forEach(p => p.classList.remove('active'));
        
        // Adicionar destaque à região
        path.classList.add('active');
        
        // Disparar evento
        const event = new CustomEvent('regionSelected', {
            detail: { regionId: regionId }
        });
        document.dispatchEvent(event);
    }
}

/**
 * Função auxiliar para limpar seleção
 */
function clearRegionSelection() {
    document.querySelectorAll('.region-path').forEach(p => p.classList.remove('active'));
}

// Exportar para uso em módulos (se necessário)
if (typeof module !== 'undefined' && module.exports) {
    module.exports = { 
        injectMap, 
        initializeMapInteractivity, 
        getRegionData, 
        highlightRegion, 
        clearRegionSelection,
        maranhaoMapData
    };
}
